import pytest
import requests

BASE_URL = "http://fhir-lite/Ingest"

@pytest.fixture
def unregistered_cert():
    return <unregistered_cert_fixture>

@pytest.fixture
def valid_observation():
    return <build_fhir_observation>(value=72.0, timestamp=<utc_now_iso8601>())

def test_unregistered_device_cert_rejected_with_401(unregistered_cert, valid_observation):
    resp = requests.post(
        BASE_URL,
        json=valid_observation,
        cert=unregistered_cert,
        headers={"Content-Type": "application/fhir+json"},
        timeout=10
    )
    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}: {resp.text}"
    body = resp.json()
    issues = body.get("issue", [])
    codes = [i.get("code") for i in issues]
    assert "security" in codes or "forbidden" in codes, (
        f"Expected security issue code, got: {codes}"
    )

import pytest
import requests

BASE_URL = "http://fhir-lite/Ingest"
HEADERS = {"Content-Type": "application/fhir+json"}

@pytest.fixture
def registered_cert():
    return <registered_cert_fixture>

@pytest.fixture
def unregistered_cert():
    return <unregistered_cert_fixture>

@pytest.fixture
def valid_observation():
    return <build_fhir_observation>(value=80.0, timestamp=<utc_now_iso8601>())

def test_decision_table_cert_and_registration_combinations(
    registered_cert, unregistered_cert, valid_observation
):
    resp_a = requests.post(
        BASE_URL, json=valid_observation, cert=registered_cert,
        headers=HEADERS, timeout=10
    )
    assert resp_a.status_code == 201, f"Case A failed: {resp_a.status_code}"
    resp_b = requests.post(
        BASE_URL, json=valid_observation, cert=unregistered_cert,
        headers=HEADERS, timeout=10
    )
    assert resp_b.status_code == 401, f"Case B failed: {resp_b.status_code}"
    resp_c = requests.post(
        BASE_URL, json=valid_observation,
        headers=HEADERS, timeout=10
    )
    assert resp_c.status_code in (401, 403), f"Case C failed: {resp_c.status_code}"
